mapper.select:
SELECT cr.id, c.course_name, c.course_code, cr.class_name, cr.class_code, u.real_name AS teacher_name, cr.student_count, cr.semester, cr.status, d.dept_name FROM class_room cr INNER JOIN course c ON c.id = cr.course_id AND c.is_deleted = 0 INNER JOIN sys_user u ON u.id = cr.teacher_id LEFT JOIN sys_dept d ON d.id = cr.dept_id
INNER JOIN class_student cs ON cs.class_id = cr.id AND cs.student_id = #{userId} AND cs.status = 1
WHERE cr.is_deleted = 0
AND cr.teacher_id = #{userId}
AND cr.semester = #{semester}
AND cr.status = #{status}
ORDER BY cr.semester DESC, cr.created_at DESC
